export const GRID_SIZE = 10;

export const SHIPS = [
    { id: 0, length: 5, name: 'Carrier', emoji: '🛥️' },
    { id: 1, length: 4, name: 'Battleship', emoji: '⛵' },
    { id: 2, length: 3, name: 'Destroyer', emoji: '🚢' },
    { id: 3, length: 3, name: 'Submarine', emoji: '🤿' },
    { id: 4, length: 2, name: 'Patrol', emoji: '🚤' },
];

export const CELL = {
    WATER: 'W',
    SHIP: 'S',
    HIT: 'H',
    MISS: 'M',
    SUNK: 'X',  // client-only: ship fully sunk
    SAFE: 'Z',  // client-only: safe zone around sunk ship
};

const isLocalhost =
    window.location.hostname === 'localhost' ||
    window.location.hostname === '127.0.0.1' ||
    window.location.hostname.startsWith('192.168.');

export const SOCKET_URL = process.env.REACT_APP_SERVER_URL ||
    (isLocalhost ? 'http://localhost:3001' : 'https://battleships-production.up.railway.app');

if (!SOCKET_URL) {
    console.error('SOCKET_URL is not set. Socket connection will fail.');
}
